import threading

class SafeCounter:
    def __init__(self):
        self.value = 0
        self.lock = threading.Lock()
    def increment(self):
        with self.lock:
            current = self.value
            self.value = current + 1
    def get(self):
        with self.lock:
            return self.value

# Tests
def test_safe_counter():
    counter = SafeCounter()
    threads = []
    for _ in range(100):
        t = threading.Thread(target=lambda: [counter.increment() for _ in range(100)])
        threads.append(t)
    for t in threads: t.start()
    for t in threads: t.join()
    assert counter.get() == 10000

