class EventEmitter:
    def __init__(self):
        self.events = {}

    def on(self, event, cb):
        if event not in self.events:
            self.events[event] = []
        self.events[event].append(cb)

    def off(self, event, cb):
        if event in self.events:
            self.events[event] = [callback for callback in self.events[event] if callback != cb]

    def emit(self, event, *args):
        if event in self.events:
            for callback in self.events[event]:
                callback(*args)

    def once(self, event, cb):
        def wrapper(*args):
            cb(*args)
            self.off(event, wrapper)
        self.on(event, wrapper)

# Tests
def test_emitter():
    e = EventEmitter(); r = []
    def cb(x): r.append(x)
    e.on("d", cb); e.emit("d", 1); e.emit("d", 2)
