def process_order(order):
    if order is None:
        return {"status": "error", "message": "no order"}

    if order.get("status") != "pending":
        return {"status": "error", "message": "order not pending"}

    if not order.get("items") or len(order["items"]) == 0:
        return {"status": "error", "message": "no items"}

    if not order.get("payment"):
        return {"status": "error", "message": "no payment info"}

    if not order["payment"].get("verified"):
        return {"status": "error", "message": "payment not verified"}

    total = sum(i["price"] * i["qty"] for i in order["items"])
    if total <= 0:
        return {"status": "error", "message": "invalid total"}

    return {"status": "processed", "total": total}

def test_process_order():
    good = {"status": "pending", "items": [{"price": 10, "qty": 2}, {"price": 5, "qty": 1}], "payment": {"verified": True}}
    r = process_order(good)
    assert r["status"] == "processed" and r["total"] == 25
    assert process_order(None)["message"] == "no order"
    assert process_order({"status": "shipped"})["message"] == "order not pending"

import random
import string

class URLShortener:
    def __init__(self):
        self.url_to_code = {}
        self.code_to_url = {}
        self.code_clicks = {}

    def _generate_code(self):
        return ''.join(random.choices(string.ascii_letters + string.digits, k=6))

    def encode(self, url):
        if url in self.url_to_code:
            return self.url_to_code[url]

        code = self._generate_code()
        while code in self.code_to_url:
            code = self._generate_code()

        self.url_to_code[url] = code
        self.code_to_url[code] = url
        self.code_clicks[code] = 0
        return code

    def decode(self, code):
        return self.code_to_url.get(code)

    def click(self, code):
        if code in self.code_clicks:
            self.code_clicks[code] += 1

    def stats(self, code):
        if code in self.code_to_url:
            return {
                "url": self.code_to_url[code],
                "clicks": self.code_clicks[code]
            }
        return None

# Tests
