class TaskScheduler:
    def __init__(self):
        self.tasks = {}
        self.visited = {}
        self.order = []

    def add_task(self, name, dependencies=[]):
        if name not in self.tasks:
            self.tasks[name] = []
        self.tasks[name].extend(dependencies)

    def get_order(self):
        self.visited = {task: 0 for task in self.tasks}  # 0 = unvisited, 1 = visiting, 2 = visited
        self.order = []

        for task in self.tasks:
            if self.visited[task] == 0:
                if not self._dfs(task):
                    raise ValueError("Cycle detected")

        return self.order[::-1]

    def _dfs(self, task):
        if self.visited[task] == 1:
            return False  # Cycle detected
        if self.visited[task] == 2:
            return True  # Already visited

        self.visited[task] = 1  # Mark as visiting

        for dependency in self.tasks[task]:
            if not self._dfs(dependency):
                return False

        self.visited[task] = 2  # Mark as visited
        self.order.append(task)
        return True

# Tests
def test_scheduler():
    s = TaskScheduler()
    s.add_task("build", ["compile"])
    s.add_task("compile", ["parse"])
    s.add_task("parse", [])
    s.add_task("test", ["build"])
    order = s.get_order()
    assert order.index("parse") < order.index("compile")
    assert order.index("compile") < order.index("build")

def test_cycle():
    s = TaskScheduler()
    s.add_task("a", ["b"])
    s.add_task("b", ["a"])
    try:
        s.get_order()
        assert False
    except ValueError:
        pass

# Run tests
test_scheduler()
test_cycle()

def evaluate(expr_string):
    def parse_expression(tokens):
        def parse_term():
            term = parse_factor()
            while tokens and tokens[0] in ('*', '/'):
                op = tokens.pop(0)
                if op == '*':
                    term *= parse_factor()
                elif op == '/':
                    term /= parse_factor()
            return term

        def parse_factor():
            factor = None
            if tokens[0] == '(':
                tokens.pop(0)  # Remove '('
                factor = parse_expression(tokens)
                tokens.pop(0)  # Remove ')'
            else:
                factor = float(tokens.pop(0))
            return factor

        expr = parse_term()
        while tokens and tokens[0] in ('+', '-'):
            op = tokens.pop(0)
            if op == '+':
                expr += parse_term()
            elif op == '-':
                expr -= parse_term()
        return expr

    # Tokenize the input string
    import re
    tokens = re.findall(r'\d+\.?\d*|[()+\-*/]', expr_string)
    return parse_expression(tokens)

