class Router:
    def __init__(self):
        self.routes = {}

    def add_route(self, method, path, handler):
        if method not in self.routes:
            self.routes[method] = []
        self.routes[method].append((self._parse_path(path), handler))

    def match(self, method, path):
        if method not in self.routes:
            return None
        for route, handler in self.routes[method]:
            params = self._match_path(route, path)
            if params is not None:
                return handler, params
        return None

    def _parse_path(self, path):
        parts = path.strip('/').split('/')
        return [part if not part.startswith(':') else ':' for part in parts]

    def _match_path(self, route, path):
        path_parts = path.strip('/').split('/')
        if len(route) != len(path_parts):
            return None
        params = {}
        for route_part, path_part in zip(route, path_parts):
            if route_part == ':':
                params['id'] = path_part
            elif route_part != path_part:
                return None
        return params

def test_router():
    r = Router()
    r.add_route("GET", "/users", lambda p: "all")
    r.add_route("GET", "/users/:id", lambda p: f"user {p['id']}")
    h, p = r.match("GET", "/users/42")
    assert p == {"id": "42"}
    assert h(p) == "user 42"
    h2, p2 = r.match("GET", "/users")
    assert h2(p2) == "all"
    assert r.match("DELETE", "/users") is None

