        self.data = collections.OrderedDict()

    def get(self, key):
        if key not in self.data:
            return None
        # Move the accessed key to the end to mark it as most recently used
        value = self.data.pop(key)
        self.data[key] = value
        return value

    def put(self, key, value):
        if key in self.data:
            # If key exists, update its value and move it to the end
            self.data.pop(key)
        elif len(self.data) >= self.max_size:
            # If cache is full and key is new, evict the least recently used item
            self.data.popitem(last=False) # last=False removes the first (LRU) item

        # Add the new key-value pair (or re-add the updated one) to the end
        self.data[key] = value

