class TaskScheduler:
    def __init__(self):
        self.graph = {}
        self.visited = {}
        self.order = []
        self.has_cycle = False

    def add_task(self, name, dependencies=[]):
        if name not in self.graph:
            self.graph[name] = []
        self.graph[name].extend(dependencies)
        for dep in dependencies:
            if dep not in self.graph:
                self.graph[dep] = []

    def get_order(self):
        self.visited = {task: False for task in self.graph}
        self.order = []
        for task in self.graph:
            if not self.visited[task]:
                self._dfs(task)
        if self.has_cycle:
            raise ValueError("Cycle detected in tasks")
        return self.order[::-1]

    def _dfs(self, task):
        if self.has_cycle:
            return
        self.visited[task] = True
        for neighbor in self.graph[task]:
            if not self.visited[neighbor]:
                self._dfs(neighbor)
            elif neighbor in self.order:
                continue
            else:
                self.has_cycle = True
                return
        self.order.append(task)

def evaluate(expr_string):
    def eval_expr(tokens):
        stack = []
        num = 0
        sign = 1  # 1 for positive, -1 for negative
        i = 0

        while i < len(tokens):
            token = tokens[i]
            if token.isdigit():
                num = int(token)
                stack.append(sign * num)
                sign = 1  # reset sign to positive
            elif token == '+':
                sign = 1
            elif token == '-':
                sign = -1
            elif token == '*':
                prev_num = stack.pop()
                i += 1
                next_num = int(tokens[i])
                stack.append(prev_num * next_num)
            elif token == '/':
                prev_num = stack.pop()
                i += 1
                next_num = int(tokens[i])
                stack.append(prev_num / next_num)
            elif token == '(':
                # Find the corresponding closing parenthesis
                j = i
                count = 1
                while count > 0:
                    j += 1
                    if tokens[j] == '(':
                        count += 1
                    elif tokens[j] == ')':
                        count -= 1
                num = eval_expr(tokens[i + 1:j])
                stack.append(sign * num)
                i = j  # Move index to the closing parenthesis
            i += 1

        return sum(stack)

    # Tokenize the input expression
    tokens = []
    num = ''
    for char in expr_string:
        if char in '0123456789':
            num += char
        else:
            if num:
                tokens.append(num)
                num = ''
            if char in '+-*/()':
                tokens.append(char)
    if num:
        tokens.append(num)

    return eval_expr(tokens)

