class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        """Insert a word into the trie."""
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word):
        """Search for an exact word in the trie."""
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    def starts_with(self, prefix):
        """Check if there is any word in the trie that starts with the given prefix."""
        node = self.root
        for char in prefix:
            if char not in node.children:
                return False
            node = node.children[char]
        return True

    def autocomplete(self, prefix, limit=5):
        """Return a list of words that start with the given prefix, up to limit."""
        node = self.root
        for char in prefix:
            if char not in node.children:
                return []
            node = node.children[char]

        results = []
        self._dfs(node, prefix, results, limit)
        return results

    def _dfs(self, node, current_word, results, limit):
        """Helper function to perform DFS and collect words."""
        if len(results) >= limit:
            return

        if node.is_end_of_word:
            results.append(current_word)

        for char in sorted(node.children.keys()):
            if len(results) >= limit:
                return
            self._dfs(node.children[char], current_word + char, results, limit)


