class EventEmitter:
    def __init__(self):
        self._events = {}

    def on(self, event, cb):
        """Register a callback for an event"""
        if event not in self._events:
            self._events[event] = []
        self._events[event].append((cb, False))
        return self

    def off(self, event, cb):
        """Unregister a callback for an event"""
        if event in self._events:
            self._events[event] = [(callback, once) for callback, once in self._events[event] if callback != cb]
        return self

    def emit(self, event, *args):
        """Emit an event with arguments"""
        if event in self._events:
            callbacks_to_remove = []
            for i, (cb, once) in enumerate(self._events[event]):
                cb(*args)
                if once:
                    callbacks_to_remove.append(i)
            # Remove once callbacks in reverse order to maintain indices
            for i in reversed(callbacks_to_remove):
                self._events[event].pop(i)
        return self

    def once(self, event, cb):
        """Register a callback that fires only once"""
        if event not in self._events:
            self._events[event] = []
        self._events[event].append((cb, True))
        return self


