def validate(data, schema):
    """
    Validate data against a schema.

    Returns:
        (bool, list): (is_valid, list_of_errors)
    """
    errors = []

    # Check if data is a dict when schema type is "dict"
    if schema.get("type") == "dict":
        if not isinstance(data, dict):
            errors.append(f"Expected dict, got {type(data).__name__}")
            return (False, errors)

    # Check required fields
    required_fields = schema.get("required", [])
    for field in required_fields:
        if field not in data:
            errors.append(f"Missing required field: {field}")

    # Check properties and their types
    properties = schema.get("properties", {})
    for field, field_schema in properties.items():
        if field in data:
            value = data[field]
            expected_type = field_schema.get("type")

            # Validate type
            if expected_type == "string":
                if not isinstance(value, str):
                    errors.append(f"Field '{field}': expected string, got {type(value).__name__}")
            elif expected_type == "int":
                if not isinstance(value, int) or isinstance(value, bool):
                    errors.append(f"Field '{field}': expected int, got {type(value).__name__}")
            elif expected_type == "dict":
                if not isinstance(value, dict):
                    errors.append(f"Field '{field}': expected dict, got {type(value).__name__}")
            elif expected_type == "list":
                if not isinstance(value, list):
                    errors.append(f"Field '{field}': expected list, got {type(value).__name__}")

    is_valid = len(errors) == 0
    return (is_valid, errors)


