class TaskScheduler:
    def __init__(self):
        self.tasks = {}
        self.dependencies = {}

    def add_task(self, name, dependencies=None):
        if dependencies is None:
            dependencies = []
        self.tasks[name] = True
        self.dependencies[name] = dependencies

    def get_order(self):
        # Detect cycles using DFS
        visited = set()
        rec_stack = set()

        def has_cycle(node):
            visited.add(node)
            rec_stack.add(node)

            for dep in self.dependencies.get(node, []):
                if dep not in visited:
                    if has_cycle(dep):
                        return True
                elif dep in rec_stack:
                    return True

            rec_stack.remove(node)
            return False

        # Check for cycles
        for task in self.tasks:
            if task not in visited:
                if has_cycle(task):
                    raise ValueError("Cycle detected in task dependencies")

        # Topological sort using DFS
        visited = set()
        order = []

        def dfs(node):
            visited.add(node)
            for dep in self.dependencies.get(node, []):
                if dep not in visited:
                    dfs(dep)
            order.append(node)

        for task in self.tasks:
            if task not in visited:
                dfs(task)

        return order


