def process_order(order):
    if order is None:
        return {"status": "error", "message": "no order"}

    if order.get("status") != "pending":
        return {"status": "error", "message": "order not pending"}

    items = order.get("items")
    if not items or len(items) == 0:
        return {"status": "error", "message": "no items"}

    payment = order.get("payment")
    if not payment:
        return {"status": "error", "message": "no payment info"}

    if not payment.get("verified"):
        return {"status": "error", "message": "payment not verified"}

    total = sum(item["price"] * item["qty"] for item in items)

    if total <= 0:
        return {"status": "error", "message": "invalid total"}

    return {"status": "processed", "total": total}

class URLShortener:
    def __init__(self):
        self.url_to_code = {}
        self.code_to_url = {}
        self.click_count = {}

    def encode(self, url: str) -> str:
        # Return existing code if URL already encoded
        if url in self.url_to_code:
            return self.url_to_code[url]

        # Generate new 6-character code
        code = self._generate_code()

        # Store mappings
        self.url_to_code[url] = code
        self.code_to_url[code] = url
        self.click_count[code] = 0

        return code

    def decode(self, code: str) -> str | None:
        # Return URL if code exists, None otherwise
        return self.code_to_url.get(code)

    def click(self, code: str) -> None:
        # Increment click count if code exists
        if code in self.click_count:
            self.click_count[code] += 1

    def stats(self, code: str) -> dict | None:
        # Return stats if code exists
        if code not in self.code_to_url:
            return None

        return {
            "url": self.code_to_url[code],
            "clicks": self.click_count[code]
        }

    def _generate_code(self) -> str:
        # Generate unique 6-character code using hash
        import hashlib
        counter = len(self.code_to_url)
        hash_obj = hashlib.md5(str(counter).encode())
        code = hash_obj.hexdigest()[:6]

        # Ensure uniqueness
        while code in self.code_to_url:
            counter += 1
            hash_obj = hashlib.md5(str(counter).encode())
            code = hash_obj.hexdigest()[:6]

        return code


def test_shortener():
    s = URLShortener()
    c = s.encode("https://example.com")
    assert len(c) == 6
    assert s.decode(c) == "https://example.com"
    assert s.encode("https://example.com") == c
    s.click(c); s.click(c)
    assert s.stats(c)["clicks"] == 2
    assert s.decode("xxxxxx") is None
    print("All tests passed!")


