class Router:
    def __init__(self):
        self.routes = []

    def add_route(self, method, path, handler):
        self.routes.append((method, path, handler))

    def match(self, method, path):
        for route_method, route_path, handler in self.routes:
            if route_method != method:
                continue

            params = self._match_path(route_path, path)
            if params is not None:
                return (handler, params)

        return None

    def _match_path(self, route_path, request_path):
        route_parts = route_path.split('/')
        request_parts = request_path.split('/')

        if len(route_parts) != len(request_parts):
            return None

        params = {}
        for route_part, request_part in zip(route_parts, request_parts):
            if route_part.startswith(':'):
                param_name = route_part[1:]
                params[param_name] = request_part
            elif route_part != request_part:
                return None

        return params


def test_router():
    r = Router()
    r.add_route("GET","/users", lambda p: "all")
    r.add_route("GET","/users/:id", lambda p: f"user {p['id']}" )
    h, p = r.match("GET","/users/42")
    assert p == {"id": "42"}
    h2, p2 = r.match("GET","/users")
    assert h2(p2) == "all"
    assert r.match("DELETE","/users") is None
    print("All tests passed!")

