def evaluate(expr_string):
    def parse_expression(tokens):
        def parse_term():
            term = parse_factor()
            while tokens and tokens[0] in ('*', '/'):
                op = tokens.pop(0)
                if op == '*':
                    term *= parse_factor()
                elif op == '/':
                    term /= parse_factor()
            return term

        def parse_factor():
            factor = None
            if tokens[0] == '(':
                tokens.pop(0)  # Remove '('
                factor = parse_expression(tokens)
                tokens.pop(0)  # Remove ')'
            else:
                factor = float(tokens.pop(0))
            return factor

        expr = parse_term()
        while tokens and tokens[0] in ('+', '-'):
            op = tokens.pop(0)
            if op == '+':
                expr += parse_term()
            elif op == '-':
                expr -= parse_term()
        return expr

    # Tokenize the input string
    import re
    tokens = re.findall(r'\d+\.?\d*|[()+\-*/]', expr_string)
    return parse_expression(tokens)

