    def add_route(self, method, path, handler):
        if method not in self.routes:
            self.routes[method] = []
        path_parts = path.strip('/').split('/')
        self.routes[method].append((path_parts, handler))

    def match(self, method, path):
        if method not in self.routes:
            return None
        path_parts = path.strip('/').split('/')
        for route_parts, handler in self.routes[method]:
            if len(route_parts) != len(path_parts):
                continue
            params = {}
            match = True
            for route_part, path_part in zip(route_parts, path_parts):
                if route_part.startswith(':'):
                    params[route_part[1:]] = path_part
                elif route_part != path_part:
                    match = False
                    break
            if match:
                return handler, params
        return None

def test_router():
    r = Router()
    r.add_route("GET", "/users", lambda p: "all")
    r.add_route("GET", "/users/:id", lambda p: f"user {p['id']}")
    h, p = r.match("GET", "/users/42")
    assert p == {"id": "42"}
    assert h(p) == "user 42"
    h2, p2 = r.match("GET", "/users")
    assert h2(p2) == "all"
    assert r.match("DELETE", "/users") is None

test_router()

