from functools import lru_cache

@lru_cache(maxsize=None)
def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n-1) + fibonacci(n-2)

def build_query(table, filters):
    query = f"SELECT * FROM {table}"
    params = []
    if filters:
        conds = []
        for k, v in filters.items():
            conds.append(f"{k} = ?")
            params.append(v)
        query += " WHERE " + " AND ".join(conds)
    return query, params

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word: str) -> bool:
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    def starts_with(self, prefix: str) -> bool:
        node = self.root
        for char in prefix:
            if char not in node.children:
                return False
            node = node.children[char]
        return True

    def autocomplete(self, prefix: str, limit: int = 5) -> list:
        node = self.root
        for char in prefix:
            if char not in node.children:
                return []
            node = node.children[char]

        results = []
        self._find_words(node, prefix, results, limit)
        return results

    def _find_words(self, node: TrieNode, prefix: str, results: list, limit: int) -> None:
        if len(results) >= limit:
            return
        if node.is_end_of_word:
            results.append(prefix)
        for char, child_node in node.children.items():
            self._find_words(child_node, prefix + char, results, limit)

def test_trie():
    trie = Trie()
    for w in ["apple","app","application","bat","ball"]: trie.insert(w)
    assert trie.search("app") is True
    assert trie.search("ap") is False
    assert trie.starts_with("app") is True
    assert set(trie.autocomplete("app")) == {"app","apple","application"}

test_trie()

def validate(data, schema):
    errors = []

    # Check if the data type matches the schema type
    if schema["type"] == "dict":
        if not isinstance(data, dict):
            return False, ["Data is not a dictionary."]

        # Check for required fields
        for field in schema.get("required", []):
            if field not in data:
                errors.append(f"Missing required field: {field}")

        # Check properties
        for field, field_schema in schema["properties"].items():
            if field in data:
                if not validate_type(data[field], field_schema["type"]):
                    errors.append(f"Field '{field}' should be of type '{field_schema['type']}'.")

    else:
        return False, ["Unsupported schema type."]

    return len(errors) == 0, errors

def validate_type(value, expected_type):
    if expected_type == "string":
        return isinstance(value, str)
    elif expected_type == "int":
        return isinstance(value, int)
    return False

def process_order(order):
    if order is None:
        return {"status": "error", "message": "no order"}

    if order.get("status") != "pending":
        return {"status": "error", "message": "order not pending"}

    if not order.get("items") or len(order["items"]) == 0:
        return {"status": "error", "message": "no items"}

    if not order.get("payment"):
        return {"status": "error", "message": "no payment info"}

    if not order["payment"].get("verified"):
        return {"status": "error", "message": "payment not verified"}

    total = sum(i["price"] * i["qty"] for i in order["items"])

    if total <= 0:
        return {"status": "error", "message": "invalid total"}

    return {"status": "processed", "total": total}

import random
import string

class URLShortener:
    def __init__(self):
        self.url_map = {}
        self.clicks_map = {}
        self.base_url = "http://short.url/"
        self.code_length = 6

    def _generate_code(self):
        return ''.join(random.choices(string.ascii_letters + string.digits, k=self.code_length))

    def encode(self, url):
        code = self._generate_code()
        while code in self.url_map:  # Ensure unique code
            code = self._generate_code()
        self.url_map[code] = url
        self.clicks_map[code] = 0
        return code

    def decode(self, code):
        return self.url_map.get(code)

    def click(self, code):
        if code in self.clicks_map:
            self.clicks_map[code] += 1

    def stats(self, code):
        if code in self.url_map:
            return {"url": self.url_map[code], "clicks": self.clicks_map[code]}
        return None

class TaskScheduler:
    def __init__(self):
        self.tasks = {}
        self.visited = {}
        self.order = []
        self.has_cycle = False

    def add_task(self, name, dependencies=[]):
        self.tasks[name] = dependencies
        self.visited[name] = False

    def get_order(self):
        for task in self.tasks:
            if not self.visited[task]:
                self._dfs(task)
                if self.has_cycle:
                    raise ValueError("Cycle detected in tasks")
        return self.order[::-1]

    def _dfs(self, task):
        if self.has_cycle:
            return
        self.visited[task] = True
        for dependency in self.tasks[task]:
            if not self.visited[dependency]:
                self._dfs(dependency)
            elif dependency in self.order:
                self.has_cycle = True
        self.order.append(task)

def evaluate(expr_string):
    def eval_expr(tokens):
        stack = []
        num = 0
        sign = 1  # 1 for positive, -1 for negative
        i = 0

        while i < len(tokens):
            token = tokens[i]
            if token.isdigit():
                num = int(token)
                stack.append(sign * num)
                sign = 1  # reset sign to positive
            elif token == '+':
                sign = 1
            elif token == '-':
                sign = -1
            elif token == '*':
                num = stack.pop() * int(tokens[i + 1])
                stack.append(num)
                i += 1  # skip the next number
            elif token == '/':
                num = stack.pop() / int(tokens[i + 1])
                stack.append(num)
                i += 1  # skip the next number
            elif token == '(':
                # Find the corresponding closing parenthesis
                j = i
                count = 1
                while count > 0:
                    j += 1
                    if tokens[j] == '(':
                        count += 1
                    elif tokens[j] == ')':
                        count -= 1
                num = eval_expr(tokens[i + 1:j])
                stack.append(sign * num)
                sign = 1  # reset sign to positive
                i = j  # move index to the closing parenthesis
            i += 1

        return sum(stack)

    # Tokenize the input expression
    tokens = []
    num = ''
    for char in expr_string:
        if char in '0123456789':
            num += char
        else:
            if num:
                tokens.append(num)
                num = ''
            if char in '+-*/()':
                tokens.append(char)
    if num:
        tokens.append(num)

    return eval_expr(tokens)

