def test_eval():
    assert evaluate("2 + 3") == 5
    assert evaluate("2 + 3 * 4") == 14
    assert evaluate("(2 + 3) * 4") == 20
    assert evaluate("10 / 2") == 5.0

test_eval()

class Router:
    def __init__(self):
        self.routes = {}

    def add_route(self, method, path, handler):
        if method not in self.routes:
            self.routes[method] = []
        self.routes[method].append((path, handler))

    def match(self, method, path):
        if method not in self.routes:
            return None

        for route_path, handler in self.routes[method]:
            params = self._match_path(route_path, path)
            if params is not None:
                return handler, params

        return None

    def _match_path(self, route_path, path):
        route_parts = route_path.split('/')
        path_parts = path.split('/')

        if len(route_parts) != len(path_parts):
            return None

        params = {}
        for route_part, path_part in zip(route_parts, path_parts):
            if route_part.startswith(':'):
                params[route_part[1:]] = path_part
            elif route_part != path_part:
                return None

        return params
